// Struct — value semantics
struct Point {
  var x: Int
  var y: Int
  // memberwise init synthesized for free
  // mutating method — required because struct is value type
  mutating func translate(dx: Int, dy: Int) { x += dx; y += dy }
}

var p = Point(x: 0, y: 0)
p.translate(dx: 1, dy: 2)

// Class — reference semantics + inheritance
class Animal {
  var name: String
  init(name: String) { self.name = name }
  func speak() -> String { "..." }
  deinit { print("\(name) freed") }
}

class Dog: Animal {
  override func speak() -> String { "Woof" }
}

let a = Dog(name: "Rex")
let b = a // same instance
print(a === b) // true

// Decision rule
// Need shared mutable state? identity? inheritance? → class
// Otherwise → struct

protocol Greetable {
  var name: String { get }
  func greet() -> String
}

// Default implementation via extension
extension Greetable {
  func greet() -> String { "Hello, \(name)" }
}

struct Person: Greetable { var name: String }
class Robot: Greetable {
  let name: String
  init(name: String) { self.name = name }
  func greet() -> String { "BEEP \(name)" } // override default
}

print(Person(name: "Alice").greet()) // Hello, Alice
print(Robot(name: "R2").greet())     // BEEP R2

// Protocol with associated type
protocol Container {
  associatedtype Item
  mutating func append(_ item: Item)
  var count: Int { get }
}

// Existential vs opaque
func makeAnyGreetable() -> any Greetable { Person(name: "X") }   // boxed
func makeSomeGreetable() -> some Greetable { Person(name: "Y") } // concrete, opaque

// Protocol composition
func log(_ thing: Greetable & CustomStringConvertible) { /* ... */ }

// Raw values
enum HTTPStatus: Int {
  case ok = 200
  case notFound = 404
  case serverError = 500
}
let status = HTTPStatus(rawValue: 404) // .notFound
print(HTTPStatus.ok.rawValue)         // 200

// Associated values — algebraic data types
enum NetworkResult<T> {
  case success(T)
  case failure(error: Error, retryable: Bool)
  case cached(T, age: TimeInterval)
}

func handle(_ r: NetworkResult<User>) {
  switch r {
  case .success(let user):
    show(user)
  case .failure(let err, retryable: true):
    retry()
  case .failure(let err, retryable: false):
    surface(err)
  case .cached(let user, age: let age) where age < 60:
    show(user)
  case .cached(let user, _):
    show(user); refresh()
  }
}

// Methods + computed properties on enums
enum Direction { case north, south, east, west
  var opposite: Direction {
    switch self {
    case .north: .south; case .south: .north
    case .east: .west; case .west: .east
    }
  }
}

// Indirect for recursion
indirect enum Tree<T> {
  case leaf(T)
  case node(Tree<T>, Tree<T>)
}

// Add helpers to stdlib types
extension String {
  var trimmed: String { trimmingCharacters(in: .whitespacesAndNewlines) }
  var isBlank: Bool { trimmed.isEmpty }
}

extension Array where Element: Numeric {
  func sum() -> Element { reduce(0, +) }
}

// Add protocol conformance to a third-party type
extension URL: Identifiable {
  public var id: String { absoluteString }
}

// Split your own type by responsibility
struct User {
  let id: UUID
  var name: String
  var email: String
}

extension User: Equatable, Hashable {}

extension User {
  // computed property — allowed
  var initials: String {
    name.split(separator: " ").compactMap { $0.first }.map(String.init).joined()
  }
  // static factory — allowed
  static func mock(_ name: String) -> User {
    User(id: UUID(), name: name, email: "\(name)@x.com")
  }
}

// Conditional conformance
extension Array: SomeProtocol where Element: SomeProtocol { /* ... */ }

// Tiny composable protocols
protocol Identifiable { var id: String { get } }
protocol Persistable { func save() throws }
protocol Loggable { func log() -> String }

extension Loggable where Self: Identifiable {
  func log() -> String { "[\(Self.self) \(id)]" }
}

// Compose behavior on a struct — no class needed
struct Order: Identifiable, Persistable, Loggable {
  let id: String
  func save() throws { /* ... */ }
}

let o = Order(id: "42")
print(o.log()) // [Order 42] — from default impl

// Old class-tree approach (avoid for app data models)
class BaseEntity {
  func save() throws {}
  func log() -> String { "" }
}
class OrderClass: BaseEntity { /* override save and log */ }

// POP boundary for testing
protocol AnalyticsClient { func track(_ event: String) }
struct ProdAnalytics: AnalyticsClient { func track(_ e: String) {} }
struct FakeAnalytics: AnalyticsClient { var events: [String] = []; mutating func track(_ e: String) { events.append(e) } }

struct ViewModel { let analytics: any AnalyticsClient }

// In a framework target
open class Widget { /* subclassable from apps */ }
public class Sealed { /* visible everywhere, NOT subclassable from outside */ }

public struct User {
  public var name: String          // visible
  internal var emailHash: String   // module-only
  private var sessionToken: String // type-only
}

// Initializers default to internal — make public explicit
public struct APIClient {
  public init() {}
  internal init(testStub: Bool) {}
}

// fileprivate vs private
struct Counter {
  private var value = 0
  fileprivate var displayValue: Int { value }
}

extension Counter { // same file
  mutating func increment() { value += 1 } // private accessible — same type, same file
}

// package — share between SwiftPM modules in the same package
package func internalHelper() {}

// Tip: lock down by default. Start private/internal, widen only when needed.

// Observers
class Profile {
  var name: String = "" {
    willSet { print("Will change \(name) → \(newValue)") }
    didSet { if name != oldValue { rebuildHeader() } }
  }
  func rebuildHeader() {}
}

// Observers fire on every set, even if value didn't change
// — guard with oldValue if you need change-only logic

// Lazy
class Report {
  let items: [Int]
  init(items: [Int]) { self.items = items }
  // Heavy computation deferred
  lazy var summary: Summary = computeSummary(items)
  // Lazy is NOT thread-safe — synchronize externally if needed
}

// Computed property
struct Rect { var w: Double; var h: Double
  var area: Double { w * h }                  // get-only
  var perimeter: Double {
    get { 2 * (w + h) }
    set { w = newValue / 4; h = newValue / 4 } // contrived setter
  }
}

// Static / class-level
class Constants {
  static let shared = Constants()    // thread-safe one-time init in Swift
  static var counter = 0             // mutable global state — careful
}
